import React from 'react';
import { AppBar, Toolbar, Typography, Box, Button } from '@mui/material';
import { Link as RouterLink } from "react-router-dom";

const Navbar = ({ onShowUpload, onShowLogin, onShowSignup, isLoggedIn, onLogout }) => {
  return (
    <AppBar position="fixed" sx={{ backgroundColor: '#3f51b5' }}>
      <Toolbar sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 2 }}>
          <Typography variant="h6" noWrap sx={{ color: 'inherit', cursor: 'pointer' }}>
            Dosya Yöneticisi
          </Typography>
          {isLoggedIn && ( // Show "Dosya Yükle" only if logged in
            <Button color="inherit" onClick={onShowUpload}>
              Dosya Yükle
            </Button>
          )}
        </Box>

        <Box>
          {isLoggedIn ? (
            <>
              {/* Kullanıcı Adı ve Soyadı */}
              {userFullName && (
                <Typography variant="body1" component="span" sx={{ mr: 2 }}>
                  Hoş Geldin, **{userFullName}**
                </Typography>
              )}
              <Button color="inherit" onClick={onShowUpload}>
                Dosya Yükle
              </Button>
              <Button color="inherit" onClick={onLogout}>
                Çıkış Yap
              </Button>
            </>
          ) : (
            <>
              <Button color="inherit" onClick={onShowLogin}>
                Giriş Yap
              </Button>
              <Button color="inherit" onClick={onShowSignup}>
                Üye Ol
              </Button>
            </>
          )}
        </Box>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
